import React, { useState } from "react";

const NotesCards = () => {

    const categoryColors = {
        Work: "bg-purple-500",
        Personal: "bg-pink-500",
        Study: "bg-yellow-400 text-black",
        Health: "bg-green-500",
        Finance: "bg-indigo-500",
        All: "bg-gray-400"
    };

    // 🔹 Dummy Data
    const [todos, setTodos] = useState([
        {
            _id: "1",
            title: "Complete React Project Complete React Project Complete React Project",
            description: "Finish the dashboard UI and connect backend APIs. Finish the dashboard UI and connect backend APIs. Finish the dashboard UI and connect backend APIs.",
            completed: false,
            category: "Work"
        },
        {
            _id: "2",
            title: "Gym Workout",
            description: "Chest and triceps workout session for 1 hour.",
            completed: true,
            category: "Health"
        },
        {
            _id: "3",
            title: "Study JavaScript",
            description: "Revise closures, promises and async/await concepts.",
            completed: false,
            category: "Study"
        },
        {
            _id: "4",
            title: "Buy Groceries",
            description: "Milk, eggs, fruits, and vegetables for the week.",
            completed: true,
            category: "Personal"
        },
        {
            _id: "5",
            title: "Budget Planning",
            description: "Plan monthly expenses and savings strategy.",
            completed: false,
            category: "Finance"
        }
    ]);

    // 🔹 Toggle Complete
    const handleToggle = (id) => {
        const updated = todos.map(todo =>
            todo._id === id
                ? { ...todo, completed: true }
                : todo
        );
        setTodos(updated);
    };

    return (
        <div className="min-h-screen bg-[rgb(35,46,88)] p-6">

            {/* 🔥 Cards Grid */}
            <div className="grid sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5">

                {todos.map((todo) => (
                    <div
                        key={todo._id}
                        className="bg-white/10 backdrop-blur-lg border border-white/20 rounded-xl p-4 text-white shadow-md hover:scale-105 transition flex flex-col justify-between h-[220px]"
                    >

                        {/* Category only */}
                        <div className="flex">
                            <span
                                className={`text-xs px-2 py-1 rounded-full ${categoryColors[todo.category] || "bg-gray-500"
                                    }`}
                            >
                                {todo.category}
                            </span>
                        </div>

                        {/* 🔹 Top */}
                        <div>
                            <h3 className="text-lg font-semibold truncate">
                                {todo.title}
                            </h3>

                            <p className="text-sm text-white/70 mt-2 line-clamp-3">
                                {todo.description}
                            </p>
                        </div>

                        {/* 🔹 Bottom */}
                        <div className="space-y-2">

                            {/* 🔹 Bottom */}
                            <div className="mt-4">

                                {todo.completed ? (
                                    <button
                                        disabled
                                        className="w-full py-2 bg-green-500 text-white rounded-lg text-sm cursor-not-allowed opacity-80"
                                    >
                                        Completed
                                    </button>
                                ) : (
                                    <button
                                        onClick={() => handleToggle(todo._id)}
                                        className="w-full py-2 bg-white text-black rounded-lg text-sm hover:bg-white/90 transition"
                                    >
                                        Mark as Completed
                                    </button>
                                )}

                            </div>

                        </div>

                    </div>
                ))}

            </div>

        </div>
    );
};

export default NotesCards;
